Code Good:
async fn transfer(pool: &PgPool, from: i64, to: i64, amount: f64) -> Result<()> {
    let mut tx = pool.begin().await?;

    let from_balance = sqlx::query_scalar!("SELECT balance FROM accounts WHERE id = $1 FOR UPDATE", from)
        .fetch_one(&mut *tx).await?;

    if from_balance < amount {
        return Err(anyhow!("insufficient funds"));
    }

    sqlx::query!("UPDATE accounts SET balance = balance - $1 WHERE id = $2", amount, from)
        .execute(&mut *tx).await?;
    sqlx::query!("UPDATE accounts SET balance = balance + $1 WHERE id = $2", amount, to)
        .execute(&mut *tx).await?;

    tx.commit().await?;
    Ok(())
}

