Code Good:
use deadpool_redis::{Config, Runtime, Pool};

let redis_pool: Pool = Config::from_url(redis_url)
    .create_pool(Some(Runtime::Tokio1))?;

async fn get_cached(pool: &Pool, key: &str) -> Option<String> {
    let mut conn = pool.get().await.ok()?;
    redis::cmd("GET").arg(key).query_async(&mut conn).await.ok()
}

async fn set_cached(pool: &Pool, key: &str, value: &str, ttl: u64) -> Result<()> {
    let mut conn = pool.get().await?;
    redis::cmd("SET").arg(key).arg(value).arg("EX").arg(ttl)
        .query_async(&mut conn).await?;
    Ok(())
}

